1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	
28	const FIRST_INSURANCE_RATE = 0.1;
29	const CURSE_RATE = 0.5;
30	const HIGH_ENCH_RATE = 0.3;
31	const HIGH_ENCH_THRESHOLD = 5;
32	const PROCESSING_FEE = 5;
33	
34	const COMPONENT_PREMIUM = 25;
35	const BLOCK_SIZE = 3;
36	const BLOCK_PREMIUM = 60;
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	const componentBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
43	
44	const isMainItem = (item: Item): boolean => !isComponent(item);
45	
46	const countByType = (items: Item[]): Map<string, number> =>
47	  items.reduce(
48	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
49	    new Map<string, number>(),
50	  );
51	
52	const componentTotal = (items: Item[]): number =>
53	  [...countByType(items.filter(isComponent)).values()].reduce(
54	    (sum, count) => sum + componentBasePremium(count),
55	    0,
56	  );
57	
58	const basePremium = (items: Item[]): number => {
59	  const mainTotal = items
60	    .filter(isMainItem)
61	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
62	  return mainTotal + componentTotal(items);
63	};
64	
65	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
66	
67	const surchargeFor = (
68	  items: Item[],
69	  qualifies: (item: Item) => boolean,
70	  rate: number,
71	): number =>
72	  items
73	    .filter((item) => isMainItem(item) && qualifies(item))
74	    .reduce((sum, item) => sum + mainItemBase(item) * rate, 0);
75	
76	const isCursed = (item: Item): boolean => item.cursed === true;
77	
78	const curseSurcharge = (items: Item[]): number =>
79	  surchargeFor(items, isCursed, CURSE_RATE);
80	
81	const isHighlyEnchanted = (item: Item): boolean =>
82	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
83	
84	const highEnchantmentSurcharge = (items: Item[]): number =>
85	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCH_RATE);
86	
87	const quotePremium = (items: Item[]): number => {
88	  const policyBase = basePremium(items);
89	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
90	  const itemSurcharges = curseSurcharge(items) + highEnchantmentSurcharge(items);
91	  return Math.ceil(policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE);
92	};
93	
94	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
95	  const results = scenario.steps.map((step) => ({
96	    premium: quotePremium(step.items),
97	  }));
98	  return { results };
99	};
